package com.vidaysalud.veterinaria.consultaservicio.client;
import com.vidaysalud.veterinaria.consultaservicio.exception.*;import lombok.RequiredArgsConstructor;import lombok.extern.slf4j.Slf4j;import org.springframework.beans.factory.annotation.Value;import org.springframework.http.HttpStatusCode;import org.springframework.stereotype.Component;import org.springframework.web.reactive.function.client.*;import java.time.Duration;
@Component @RequiredArgsConstructor @Slf4j
public class CitaClient{private final WebClient.Builder builder;@Value("${servicios.cita.url}")private String baseUrl;public void validar(Integer id){try{builder.build().get().uri(baseUrl+"/"+id).retrieve().onStatus(HttpStatusCode::is4xxClientError,r->r.createException().map(e->new ReglaNegocioException("Cita no existe con id: "+id))).toBodilessEntity().block(Duration.ofSeconds(4));log.info("Cita remoto válido id={}",id);}catch(ReglaNegocioException e){throw e;}catch(WebClientRequestException e){throw new ServicioRemotoException("No fue posible conectar con cita-servicio");}catch(Exception e){throw new ServicioRemotoException("Error consultando cita-servicio");}}}
